class Solution:
    def deleteAndEarn(self, nums: List[int]) -> int:
        mx = max(nums)
        cnt = [0]*(mx+1)
        for x in nums: cnt[x] += x
        prev2 = prev1 = 0
        for v in range(mx+1):
            cur = max(prev1, prev2 + cnt[v])
            prev2, prev1 = prev1, cur
        return prev1

