class Solution {
public:
    int deleteAndEarn(vector<int>& nums) {
        int mx=*max_element(nums.begin(), nums.end());
        vector<int> earn(mx+1);
        for(int x:nums) earn[x]+=x;
        int p2=0,p1=0;
        for(int v=0;v<=mx;v++){
            int cur=max(p1,p2+earn[v]);
            p2=p1; p1=cur;
        }
        return p1;
    }
};

