int deleteAndEarn(int* nums, int n) {
    int mx = 0; for (int i = 0; i < n; i++) if (nums[i] > mx) mx = nums[i];
    int* earn = calloc(mx + 1, 4);
    for (int i = 0; i < n; i++) earn[nums[i]] += nums[i];
    int p2 = 0, p1 = 0;
    for (int v = 0; v <= mx; v++) {
        int cur = p1 > p2 + earn[v] ? p1 : p2 + earn[v];
        p2 = p1; p1 = cur;
    }
    free(earn); return p1;
}
